using UnityEngine;
using System.Collections.Generic;

/// <summary>
/// Procedurally generates race tracks with configurable difficulty.
/// Ensures consistent training across NEAT generations and PPO episodes.
/// </summary>
namespace CarExperiment
{
    public class TrackGenerator : MonoBehaviour
    {
        [Header("Track Prefabs")] [Tooltip("Straight road piece prefab")]
        public GameObject straightPiece;

        [Tooltip("45-degree turn piece prefab")]
        public GameObject turn45Piece;

        [Tooltip("Goal/checkpoint piece prefab")]
        public GameObject goalPiece;

        [Header("Track Configuration")] [Tooltip("Number of road pieces in the track")]
        public int trackLength = 20;

        [Tooltip("Maximum attempts to generate a valid non-intersecting track before giving up")]
        public int maxGenerationAttempts = 10;

        [Tooltip("Difficulty level (0-1): 0=easy (mostly straight), 1=hard (many turns)")] [Range(0f, 1f)]
        public float difficulty = 0.5f;

        [Tooltip("Probability of 90-degree turn vs 45-degree turn at high difficulty")] [Range(0f, 1f)]
        public float sharpTurnProbability = 0.3f;

        [Tooltip("Random seed for reproducible tracks (0 = random seed)")]
        public int seed = 0;

        [Header("Curriculum Learning")] [Tooltip("Gradually increase difficulty over generations/episodes")]
        public bool useCurriculum = false;

        [Tooltip("Starting difficulty for curriculum")] [Range(0f, 1f)]
        public float startDifficulty = 0.1f;

        [Tooltip("Episodes/generations to reach max difficulty")]
        public int curriculumSteps = 100;

        [Header("Track Appearance")] [Tooltip("Width of each road piece")]
        public float pieceLength = 2f;

        [Tooltip("Number of wall segments to use on turns to follow curvature")]
        public int wallSegmentsPerTurn = 8;

        [Tooltip("Thickness of the wall (X scale contribution)")]
        public float wallThickness = 0.05f;

        [Header("Track Walls")] [Tooltip("Wall prefab to instantiate along the track")]
        public GameObject wallPrefab;

        [Tooltip("Distance from road center to wall (half road width + half wall width)")]
        public float wallOffset = 2.7f;

        [Header("Wall Trimming")]
        [Tooltip("Inset amount to trim the right wall before a right turn (in meters)")]
        public float wallEndInset = 2f;

        private Vector3 lastWallEndL = Vector3.zero;
        private Vector3 lastWallEndR = Vector3.zero;
        private Quaternion lastPieceRot = Quaternion.identity;

        // Track data
        private List<GameObject> currentTrackPieces;
        private List<GameObject> currentWallPieces;
        private Vector3 currentPosition;
        private Quaternion currentRotation;
        private int generationCount = 0;

        // Track statistics (for analysis)
        public struct TrackStats
        {
            public int StraightCount;
            public int Turn45Count;
            public float TotalTurnAngle;
            public float ActualDifficulty;
        }

        private struct PieceInfo
        {
            public PieceType Type;
            public Vector3 Pos;
            public Quaternion Rot;
        }

        private TrackStats lastTrackStats;

        void Start()
        {
            currentTrackPieces = new List<GameObject>();
            currentWallPieces = new List<GameObject>();
            GenerateTrack(Random.Range(0, 1000000));;
        }

        /// <summary>
        /// Generates a new procedural track. Call this at the start of each NEAT generation or PPO episode.
        /// </summary>
        ///
        public void GenerateTrack(int externalSeed)
        {
            // Force deterministic generation
            Random.InitState(externalSeed);

            GenerateNewTrackWithSeed();
        }

        public void GenerateNewTrackWithSeed()
        {

            ClearTrack();
            generationCount++;

            // Set random seed for reproducibility if specified
            // if (seed != 0)
            // {
            //     Random.InitState(seed + generationCount);
            // }

            List<TrackGenerator.PieceInfo> pieces = new List<TrackGenerator.PieceInfo>();
            bool generationSuccessful = false;
            int attempts = 0;

            while (!generationSuccessful && attempts < maxGenerationAttempts)
            {
                attempts++;
                pieces.Clear();
                Vector3 tempPos = transform.position;
                Quaternion tempRot = transform.rotation;
                PieceType nextType = PieceType.Straight;
                bool foundIntersectionInThisAttempt = false;

                for (int i = 0; i < trackLength; i++)
                {
                    if (i == trackLength - 1)
                    {
                        pieces.Add(new TrackGenerator.PieceInfo { Type = PieceType.Straight, Pos = tempPos, Rot = tempRot });
                    }
                    else
                    {
                        // Intersection check and piece selection
                        PieceType selected = nextType;
                        // Try types in this order: desired, straight, left, right
                        PieceType[] attemptTypes = { nextType, PieceType.Straight, PieceType.Turn45Left, PieceType.Turn45Right, PieceType.Turn90Left, PieceType.Turn90Right };
                        bool foundValidPiece = false;

                        foreach (PieceType attempt in attemptTypes)
                        {
                            Vector3 nextPos = GetNextPosition(tempPos, tempRot, attempt);
                            bool intersects = false;

                            // Start checking against previous pieces (skip the immediate previous one)
                            for (int j = 0; j < pieces.Count - 1; j++)
                            {
                                if (Vector3.Distance(nextPos, pieces[j].Pos) < pieceLength * 1.5f)
                                {
                                    intersects = true;
                                    break;
                                }
                            }

                            if (!intersects)
                            {
                                selected = attempt;
                                foundValidPiece = true;
                                break;
                            }
                        }

                        if (!foundValidPiece)
                        {
                            foundIntersectionInThisAttempt = true;
                            break; // Fail this entire track attempt
                        }

                        pieces.Add(new TrackGenerator.PieceInfo { Type = selected, Pos = tempPos, Rot = tempRot });
                        tempPos = GetNextPosition(tempPos, tempRot, selected);
                        tempRot = GetNextRotation(tempRot, selected);
                        nextType = SelectPieceType(CalculateCurrentDifficulty());
                    }
                }

                if (!foundIntersectionInThisAttempt)
                {
                    generationSuccessful = true;
                }
            }

            lastWallEndL = Vector3.zero;
            lastWallEndR = Vector3.zero;

            TrackStats stats = new TrackStats();
            for (int i = 0; i < pieces.Count; i++)
            {
                TrackGenerator.PieceInfo info = pieces[i];
                GameObject piece;

                if (i == trackLength - 1)
                {
                    piece = Instantiate(goalPiece, info.Pos, info.Rot, transform);
                    piece.name = $"Goal_Piece_{i}";
                    var teleport = piece.AddComponent<GoalTeleport>();
                }
                else
                {
                    switch (info.Type)
                    {
                        case PieceType.Straight:
                            piece = Instantiate(straightPiece, info.Pos, info.Rot, transform);
                            piece.name = $"Straight_Piece_{i}";
                            stats.StraightCount++;
                            break;
                        case PieceType.Turn45Left:
                            piece = Instantiate(turn45Piece, info.Pos, info.Rot, transform);
                            piece.name = $"Turn45L_Piece_{i}";
                            stats.Turn45Count++;
                            stats.TotalTurnAngle += 45f;
                            break;
                        case PieceType.Turn45Right:
                            piece = Instantiate(turn45Piece, info.Pos, info.Rot, transform);
                            piece.name = $"Turn45R_Piece_{i}";
                            stats.Turn45Count++;
                            stats.TotalTurnAngle += 45f;
                            break;
                        case PieceType.Turn90Left:
                            piece = Instantiate(turn45Piece, info.Pos, info.Rot, transform);
                            piece.name = $"Turn90L_Piece_{i}";
                            stats.Turn45Count++;
                            stats.TotalTurnAngle += 90f;
                            break;
                        case PieceType.Turn90Right:
                            piece = Instantiate(turn45Piece, info.Pos, info.Rot, transform);
                            piece.name = $"Turn90R_Piece_{i}";
                            stats.Turn45Count++;
                            stats.TotalTurnAngle += 90f;
                            break;
                        default:
                            piece = Instantiate(straightPiece, info.Pos, info.Rot, transform);
                            piece.name = $"Default_Piece_{i}";
                            stats.StraightCount++;
                            break;
                    }
                }

                currentTrackPieces.Add(piece);

                // Set PieceNumber for road pieces (not goal)
                if (i < trackLength - 1)
                {
                    RoadPiece rp = piece.GetComponentInChildren<RoadPiece>();
                    if (rp != null)
                    {
                        rp.PieceNumber = i;
                    }
                }

                if (wallPrefab != null && i < pieces.Count - 1)
                {
                    // Start from where the previous wall ended (or compute fresh for piece 0)
                    Vector3 wallStartL = (lastWallEndL != Vector3.zero)
                        ? lastWallEndL
                        : info.Pos + info.Rot * (Vector3.left * wallOffset);

                    Vector3 wallStartR = (lastWallEndR != Vector3.zero)
                        ? lastWallEndR
                        : info.Pos + info.Rot * (Vector3.right * wallOffset);

                    Quaternion exitRot = GetNextRotation(info.Rot, info.Type);
                    Vector3 exitPos = GetNextPosition(info.Pos, info.Rot, info.Type);

                    Vector3 wallEndL = exitPos + exitRot * (Vector3.left * wallOffset);
                    Vector3 wallEndR = exitPos + exitRot * (Vector3.right * wallOffset);

                    if (pieces[i + 1].Type == PieceType.Turn45Left)
                        wallEndL = wallEndL - exitRot * (Vector3.forward * wallEndInset);

                    if (pieces[i + 1].Type == PieceType.Turn45Right)
                        wallEndR = wallEndR - exitRot * (Vector3.forward * wallEndInset);

                    if (pieces[i + 1].Type == PieceType.Turn90Left)
                        wallEndL = wallEndL - exitRot * (Vector3.forward * wallEndInset * 2f);

                    if (pieces[i + 1].Type == PieceType.Turn90Right)
                        wallEndR = wallEndR - exitRot * (Vector3.forward * wallEndInset * 2f);

                    // Trim the INNER side before a turn, and save that trimmed point
                    // so the turn piece's inner wall can start exactly from there
                    // if (pieces[i + 1].Type == PieceType.Turn45Left)
                    //     wallEndL = wallEndL - info.Rot * (Vector3.forward * wallEndInset);
                    //
                    // if (pieces[i + 1].Type == PieceType.Turn45Right)
                    //     wallEndR = wallEndR - info.Rot * (Vector3.forward * wallEndInset);

                    lastWallEndL = wallEndL;
                    lastWallEndR = wallEndR;

                    PlaceWall(wallStartL, wallEndL, $"WallL_{i}", wallThickness);
                    PlaceWall(wallStartR, wallEndR, $"WallR_{i}", wallThickness);

                    // After placing walls, store current piece's rotation for next iteration
                    lastPieceRot = info.Rot;
                    if (i == 0)
                    {
                        Vector3 backL = info.Pos + info.Rot * (Vector3.left * wallOffset);
                        Vector3 backR = info.Pos + info.Rot * (Vector3.right * wallOffset);
                        PlaceWall(backL, backR, "BackWall", wallThickness);
                    }
                }
            }

            // Removed stray currentWallPieces.Add(wall); which was outside any function and caused errors.
        }

        private Vector3 GetNextPosition(Vector3 startPos, Quaternion startRot, PieceType type)
        {
            Vector3 pos = startPos;
            Quaternion rot = startRot;
            if (type == PieceType.Turn45Left)
            {
                rot *= Quaternion.Euler(0, -45, 0);
                pos += rot * (-Vector3.right * 0.78641f + -Vector3.forward * 1.66428f);
            }
            else if (type == PieceType.Turn45Right)
            {
                rot *= Quaternion.Euler(0, 45, 0);
                pos += rot * (Vector3.right * 0.78641f + -Vector3.forward * 1.66428f);
            }
            else if (type == PieceType.Turn90Left)
            {
                rot *= Quaternion.Euler(0, -90, 0);
                // For 90-degree turns, the offset is purely lateral and forward
                pos += rot * (-Vector3.right * 2f + -Vector3.forward * 2f);
            }
            else if (type == PieceType.Turn90Right)
            {
                rot *= Quaternion.Euler(0, 90, 0);
                // For 90-degree turns, the offset is purely lateral and forward
                pos += rot * (Vector3.right * 2f + -Vector3.forward * 2f);
            }
            pos += rot * Vector3.forward * pieceLength;
            return pos;
        }

        private Quaternion GetNextRotation(Quaternion startRot, PieceType type)
        {
            Quaternion rot = startRot;
            if (type == PieceType.Turn45Left)
            {
                rot *= Quaternion.Euler(0, -45, 0);
            }
            else if (type == PieceType.Turn45Right)
            {
                rot *= Quaternion.Euler(0, 45, 0);
            }
            else if (type == PieceType.Turn90Left)
            {
                rot *= Quaternion.Euler(0, -90, 0);
            }
            else if (type == PieceType.Turn90Right)
            {
                rot *= Quaternion.Euler(0, 90, 0);
            }
            return rot;
        }

        /// <summary>
        /// Selects a piece type based on current difficulty and previous piece orientation.
        /// </summary>
        private PieceType SelectPieceType(float currentDifficulty)
        {
            float roll = Random.value;

            // At low difficulty, mostly straight pieces
            // At high difficulty, more turns
            if (roll > currentDifficulty)
            {
                return PieceType.Straight;
            }
            else
            {
                // Choose between 45-degree and 90-degree turns based on sharpTurnProbability
                bool useSharpTurn = Random.value < sharpTurnProbability;
                bool turnLeft = Random.value < 0.5f;

                if (useSharpTurn)
                {
                    return turnLeft ? PieceType.Turn90Left : PieceType.Turn90Right;
                }
                else
                {
                    return turnLeft ? PieceType.Turn45Left : PieceType.Turn45Right;
                }
            }
        }

        /// <summary>
        /// Calculates current difficulty based on curriculum settings.
        /// </summary>
        private float CalculateCurrentDifficulty()
        {
            if (!useCurriculum)
            {
                return difficulty;
            }

            // Gradually increase from startDifficulty to difficulty over curriculumSteps
            float progress = Mathf.Min(generationCount / (float)curriculumSteps, 1f);
            return Mathf.Lerp(startDifficulty, difficulty, progress);
        }

        /// <summary>
        /// Clears the current track.
        /// </summary>
        private void ClearTrack()
        {
            foreach (GameObject piece in currentTrackPieces)
            {
                Destroy(piece);
            }

            currentTrackPieces.Clear();
            foreach (GameObject wall in currentWallPieces)
            {
                Destroy(wall);
            }

            currentWallPieces.Clear();
        }

        /// <summary>
        /// Gets statistics about the last generated track (for thesis analysis).
        /// </summary>
        public TrackStats GetLastTrackStats()
        {
            return lastTrackStats;
        }

        /// <summary>
        /// Gets the current generation/episode count.
        /// </summary>
        public int GetGenerationCount()
        {
            return generationCount;
        }

        /// <summary>
        /// Resets the generation counter (useful when switching between NEAT/PPO experiments).
        /// </summary>
        public void ResetGenerationCount()
        {
            generationCount = 0;
        }

        void OnDrawGizmos()
        {
            // Visualize track in editor
            if (currentTrackPieces.Count > 0)
            {
                Gizmos.color = Color.cyan;
                for (int i = 0; i < currentTrackPieces.Count - 1; i++)
                {
                    Gizmos.DrawLine(
                        currentTrackPieces[i].transform.position + Vector3.up * 0.5f,
                        currentTrackPieces[i + 1].transform.position + Vector3.up * 0.5f
                    );
                }
            }
        }

        private void PlaceWall(Vector3 start, Vector3 end, string wallName, float thickness)
        {
            Vector3 diff = end - start;
            //Debug.Log(end + " - " + start + " = " + diff);
            float dist = diff.magnitude;
            if (dist < 0.001f) return;

            Vector3 wallPos = start + diff * 0.5f;
            Quaternion wallRot = Quaternion.LookRotation(diff);

            GameObject wall = Instantiate(wallPrefab, wallPos, wallRot, transform);
            wall.name = wallName;

            // Clean scale: thickness (X), height (Y), and distance (Z)
            // Use 1.0f for Y to preserve prefab height relative to its transform
            wall.transform.localScale = new Vector3(thickness, wall.transform.localScale.y, dist);

            currentWallPieces.Add(wall);
        }

        private enum PieceType
        {
            Straight,
            Turn45Left,
            Turn45Right,
            Turn90Left,
            Turn90Right
        }
    }
}

using UnityEngine;
using System.Collections.Generic;

/// <summary>
/// Procedurally generates race tracks with configurable difficulty.
/// Ensures consistent training across NEAT generations and PPO episodes.
/// </summary>
namespace CarExperiment
{
    public class TrackGenerator : MonoBehaviour
    {
        [Header("Track Prefabs")] [Tooltip("Straight road piece prefab")]
        public GameObject straightPiece;

        [Tooltip("45-degree turn piece prefab")]
        public GameObject turn45Piece;

        [Tooltip("Goal/checkpoint piece prefab")]
        public GameObject goalPiece;

        [Header("Track Configuration")] [Tooltip("Number of road pieces in the track")]
        public int trackLength = 20;

        [Tooltip("Maximum attempts to generate a valid non-intersecting track before giving up")]
        public int maxGenerationAttempts = 10;

        [Tooltip("Difficulty level (0-1): 0=easy (mostly straight), 1=hard (many turns)")] [Range(0f, 1f)]
        public float difficulty = 0.5f;

        [Tooltip("Probability of 90-degree turn vs 45-degree turn at high difficulty")] [Range(0f, 1f)]
        public float sharpTurnProbability = 0.3f;

        [Tooltip("Random seed for reproducible tracks (0 = random seed)")]
        public int seed = 0;

        [Header("Curriculum Learning")] [Tooltip("Gradually increase difficulty over generations/episodes")]
        public bool useCurriculum = false;

        [Tooltip("Starting difficulty for curriculum")] [Range(0f, 1f)]
        public float startDifficulty = 0.1f;

        [Tooltip("Episodes/generations to reach max difficulty")]
        public int curriculumSteps = 100;

        [Header("Track Appearance")] [Tooltip("Width of each road piece")]
        public float pieceLength = 2f;

        [Tooltip("Number of wall segments to use on turns to follow curvature")]
        public int wallSegmentsPerTurn = 8;

        [Tooltip("Thickness of the wall (X scale contribution)")]
        public float wallThickness = 0.05f;

        [Header("Track Walls")] [Tooltip("Wall prefab to instantiate along the track")]
        public GameObject wallPrefab;

        [Tooltip("Distance from road center to wall (half road width + half wall width)")]
        public float wallOffset = 2.7f;

        [Header("Wall Trimming")]
        [Tooltip("Inset amount to trim the right wall before a right turn (in meters)")]
        public float wallEndInset = 2f;

        private Vector3 lastWallEndL = Vector3.zero;
        private Vector3 lastWallEndR = Vector3.zero;
        private Quaternion lastPieceRot = Quaternion.identity;

        // Track data
        private List<GameObject> currentTrackPieces;
        private List<GameObject> currentWallPieces;
        private Vector3 currentPosition;
        private Quaternion currentRotation;
        private int generationCount = 0;

        // Track statistics (for analysis)
        public struct TrackStats
        {
            public int StraightCount;
            public int Turn45Count;
            public float TotalTurnAngle;
            public float ActualDifficulty;
        }

        private struct PieceInfo
        {
            public PieceType Type;
            public Vector3 Pos;
            public Quaternion Rot;
        }

        private TrackStats lastTrackStats;

        void Start()
        {
            currentTrackPieces = new List<GameObject>();
            currentWallPieces = new List<GameObject>();
            GenerateTrack(Random.Range(0, 1000000));;
        }

        /// <summary>
        /// Generates a new procedural track. Call this at the start of each NEAT generation or PPO episode.
        /// </summary>
        /// 
        public void GenerateTrack(int externalSeed)
        {
            // Force deterministic generation
            Random.InitState(externalSeed);

            GenerateNewTrackWithSeed();
        }

        public void GenerateNewTrackWithSeed()
        {

            ClearTrack();
            generationCount++;

            // Set random seed for reproducibility if specified
            // if (seed != 0)
            // {
            //     Random.InitState(seed + generationCount);
            // }

            List<TrackGenerator.PieceInfo> pieces = new List<TrackGenerator.PieceInfo>();
            bool generationSuccessful = false;
            int attempts = 0;

            while (!generationSuccessful && attempts < maxGenerationAttempts)
            {
                attempts++;
                pieces.Clear();
                Vector3 tempPos = transform.position;
                Quaternion tempRot = transform.rotation;
                PieceType nextType = PieceType.Straight;
                bool foundIntersectionInThisAttempt = false;

                for (int i = 0; i < trackLength; i++)
                {
                    if (i == trackLength - 1)
                    {
                        pieces.Add(new TrackGenerator.PieceInfo { Type = PieceType.Straight, Pos = tempPos, Rot = tempRot });
                    }
                    else
                    {
                        // Intersection check and piece selection
                        PieceType selected = nextType;
                        // Try types in this order: desired, straight, left, right
                        PieceType[] attemptTypes = { nextType, PieceType.Straight, PieceType.Turn45Left, PieceType.Turn45Right, PieceType.Turn90Left, PieceType.Turn90Right };
                        bool foundValidPiece = false;

                        foreach (PieceType attempt in attemptTypes)
                        {
                            Vector3 nextPos = GetNextPosition(tempPos, tempRot, attempt);
                            bool intersects = false;

                            // Start checking against previous pieces (skip the immediate previous one)
                            for (int j = 0; j < pieces.Count - 1; j++)
                            {
                                if (Vector3.Distance(nextPos, pieces[j].Pos) < pieceLength * 1.5f)
                                {
                                    intersects = true;
                                    break;
                                }
                            }

                            if (!intersects)
                            {
                                selected = attempt;
                                foundValidPiece = true;
                                break;
                            }
                        }

                        if (!foundValidPiece)
                        {
                            foundIntersectionInThisAttempt = true;
                            break; // Fail this entire track attempt
                        }

                        pieces.Add(new TrackGenerator.PieceInfo { Type = selected, Pos = tempPos, Rot = tempRot });
                        tempPos = GetNextPosition(tempPos, tempRot, selected);
                        tempRot = GetNextRotation(tempRot, selected);
                        nextType = SelectPieceType(CalculateCurrentDifficulty());
                    }
                }

                if (!foundIntersectionInThisAttempt)
                {
                    generationSuccessful = true;
                }
            }

            lastWallEndL = Vector3.zero;
            lastWallEndR = Vector3.zero;

            TrackStats stats = new TrackStats();
            for (int i = 0; i < pieces.Count; i++)
            {
                TrackGenerator.PieceInfo info = pieces[i];
                GameObject piece;

                if (i == trackLength - 1)
                {
                    piece = Instantiate(goalPiece, info.Pos, info.Rot, transform);
                    piece.name = $"Goal_Piece_{i}";
                    var teleport = piece.AddComponent<GoalTeleport>();
                }
                else
                {
                    switch (info.Type)
                    {
                        case PieceType.Straight:
                            piece = Instantiate(straightPiece, info.Pos, info.Rot, transform);
                            piece.name = $"Straight_Piece_{i}";
                            stats.StraightCount++;
                            break;
                        case PieceType.Turn45Left:
                            piece = Instantiate(turn45Piece, info.Pos, info.Rot, transform);
                            piece.name = $"Turn45L_Piece_{i}";
                            stats.Turn45Count++;
                            stats.TotalTurnAngle += 45f;
                            break;
                        case PieceType.Turn45Right:
                            piece = Instantiate(turn45Piece, info.Pos, info.Rot, transform);
                            piece.name = $"Turn45R_Piece_{i}";
                            stats.Turn45Count++;
                            stats.TotalTurnAngle += 45f;
                            break;
                        case PieceType.Turn90Left:
                            piece = Instantiate(turn45Piece, info.Pos, info.Rot, transform);
                            piece.name = $"Turn90L_Piece_{i}";
                            stats.Turn45Count++;
                            stats.TotalTurnAngle += 90f;
                            break;
                        case PieceType.Turn90Right:
                            piece = Instantiate(turn45Piece, info.Pos, info.Rot, transform);
                            piece.name = $"Turn90R_Piece_{i}";
                            stats.Turn45Count++;
                            stats.TotalTurnAngle += 90f;
                            break;
                        default:
                            piece = Instantiate(straightPiece, info.Pos, info.Rot, transform);
                            piece.name = $"Default_Piece_{i}";
                            stats.StraightCount++;
                            break;
                    }
                }

                currentTrackPieces.Add(piece);

                // Set PieceNumber for road pieces (not goal)
                if (i < trackLength - 1)
                {
                    RoadPiece rp = piece.GetComponentInChildren<RoadPiece>();
                    if (rp != null)
                    {
                        rp.PieceNumber = i;
                    }
                }

                if (wallPrefab != null && i < pieces.Count - 1)
                {
                    // Start from where the previous wall ended (or compute fresh for piece 0)
                    Vector3 wallStartL = (lastWallEndL != Vector3.zero)
                        ? lastWallEndL
                        : info.Pos + info.Rot * (Vector3.left * wallOffset);

                    Vector3 wallStartR = (lastWallEndR != Vector3.zero)
                        ? lastWallEndR
                        : info.Pos + info.Rot * (Vector3.right * wallOffset);

                    Quaternion exitRot = GetNextRotation(info.Rot, info.Type);
                    Vector3 exitPos = GetNextPosition(info.Pos, info.Rot, info.Type);

                    Vector3 wallEndL = exitPos + exitRot * (Vector3.left * wallOffset);
                    Vector3 wallEndR = exitPos + exitRot * (Vector3.right * wallOffset);

                    if (pieces[i + 1].Type == PieceType.Turn45Left)
                        wallEndL = wallEndL - exitRot * (Vector3.forward * wallEndInset);

                    if (pieces[i + 1].Type == PieceType.Turn45Right)
                        wallEndR = wallEndR - exitRot * (Vector3.forward * wallEndInset);

                    if (pieces[i + 1].Type == PieceType.Turn90Left)
                        wallEndL = wallEndL - exitRot * (Vector3.forward * wallEndInset * 2f);

                    if (pieces[i + 1].Type == PieceType.Turn90Right)
                        wallEndR = wallEndR - exitRot * (Vector3.forward * wallEndInset * 2f);

                    // Trim the INNER side before a turn, and save that trimmed point
                    // so the turn piece's inner wall can start exactly from there
                    // if (pieces[i + 1].Type == PieceType.Turn45Left)
                    //     wallEndL = wallEndL - info.Rot * (Vector3.forward * wallEndInset);
                    //
                    // if (pieces[i + 1].Type == PieceType.Turn45Right)
                    //     wallEndR = wallEndR - info.Rot * (Vector3.forward * wallEndInset);

                    lastWallEndL = wallEndL;
                    lastWallEndR = wallEndR;

                    PlaceWall(wallStartL, wallEndL, $"WallL_{i}", wallThickness);
                    PlaceWall(wallStartR, wallEndR, $"WallR_{i}", wallThickness);

                    // After placing walls, store current piece's rotation for next iteration
                    lastPieceRot = info.Rot;
                    if (i == 0)
                    {
                        Vector3 backL = info.Pos + info.Rot * (Vector3.left * wallOffset);
                        Vector3 backR = info.Pos + info.Rot * (Vector3.right * wallOffset);
                        PlaceWall(backL, backR, "BackWall", wallThickness);
                    }
                }
            }

            // Removed stray currentWallPieces.Add(wall); which was outside any function and caused errors.
        }

        private Vector3 GetNextPosition(Vector3 startPos, Quaternion startRot, PieceType type)
        {
            Vector3 pos = startPos;
            Quaternion rot = startRot;
            if (type == PieceType.Turn45Left)
            {
                rot *= Quaternion.Euler(0, -45, 0);
                pos += rot * (-Vector3.right * 0.78641f + -Vector3.forward * 1.66428f);
            }
            else if (type == PieceType.Turn45Right)
            {
                rot *= Quaternion.Euler(0, 45, 0);
                pos += rot * (Vector3.right * 0.78641f + -Vector3.forward * 1.66428f);
            }
            else if (type == PieceType.Turn90Left)
            {
                rot *= Quaternion.Euler(0, -90, 0);
                // For 90-degree turns, the offset is purely lateral and forward
                pos += rot * (-Vector3.right * 2f + -Vector3.forward * 2f);
            }
            else if (type == PieceType.Turn90Right)
            {
                rot *= Quaternion.Euler(0, 90, 0);
                // For 90-degree turns, the offset is purely lateral and forward
                pos += rot * (Vector3.right * 2f + -Vector3.forward * 2f);
            }
            pos += rot * Vector3.forward * pieceLength;
            return pos;
        }

        private Quaternion GetNextRotation(Quaternion startRot, PieceType type)
        {
            Quaternion rot = startRot;
            if (type == PieceType.Turn45Left)
            {
                rot *= Quaternion.Euler(0, -45, 0);
            }
            else if (type == PieceType.Turn45Right)
            {
                rot *= Quaternion.Euler(0, 45, 0);
            }
            else if (type == PieceType.Turn90Left)
            {
                rot *= Quaternion.Euler(0, -90, 0);
            }
            else if (type == PieceType.Turn90Right)
            {
                rot *= Quaternion.Euler(0, 90, 0);
            }
            return rot;
        }

        /// <summary>
        /// Selects a piece type based on current difficulty and previous piece orientation.
        /// </summary>
        private PieceType SelectPieceType(float currentDifficulty)
        {
            float roll = Random.value;

            // At low difficulty, mostly straight pieces
            // At high difficulty, more turns
            if (roll > currentDifficulty)
            {
                return PieceType.Straight;
            }
            else
            {
                // Choose between 45-degree and 90-degree turns based on sharpTurnProbability
                bool useSharpTurn = Random.value < sharpTurnProbability;
                bool turnLeft = Random.value < 0.5f;

                if (useSharpTurn)
                {
                    return turnLeft ? PieceType.Turn90Left : PieceType.Turn90Right;
                }
                else
                {
                    return turnLeft ? PieceType.Turn45Left : PieceType.Turn45Right;
                }
            }
        }

        /// <summary>
        /// Calculates current difficulty based on curriculum settings.
        /// </summary>
        private float CalculateCurrentDifficulty()
        {
            if (!useCurriculum)
            {
                return difficulty;
            }

            // Gradually increase from startDifficulty to difficulty over curriculumSteps
            float progress = Mathf.Min(generationCount / (float)curriculumSteps, 1f);
            return Mathf.Lerp(startDifficulty, difficulty, progress);
        }

        /// <summary>
        /// Clears the current track.
        /// </summary>
        private void ClearTrack()
        {
            foreach (GameObject piece in currentTrackPieces)
            {
                Destroy(piece);
            }

            currentTrackPieces.Clear();
            foreach (GameObject wall in currentWallPieces)
            {
                Destroy(wall);
            }

            currentWallPieces.Clear();
        }

        /// <summary>
        /// Gets statistics about the last generated track (for thesis analysis).
        /// </summary>
        public TrackStats GetLastTrackStats()
        {
            return lastTrackStats;
        }

        /// <summary>
        /// Gets the current generation/episode count.
        /// </summary>
        public int GetGenerationCount()
        {
            return generationCount;
        }

        /// <summary>
        /// Resets the generation counter (useful when switching between NEAT/PPO experiments).
        /// </summary>
        public void ResetGenerationCount()
        {
            generationCount = 0;
        }

        void OnDrawGizmos()
        {
            // Visualize track in editor
            if (currentTrackPieces.Count > 0)
            {
                Gizmos.color = Color.cyan;
                for (int i = 0; i < currentTrackPieces.Count - 1; i++)
                {
                    Gizmos.DrawLine(
                        currentTrackPieces[i].transform.position + Vector3.up * 0.5f,
                        currentTrackPieces[i + 1].transform.position + Vector3.up * 0.5f
                    );
                }
            }
        }

        private void PlaceWall(Vector3 start, Vector3 end, string wallName, float thickness)
        {
            Vector3 diff = end - start;
            //Debug.Log(end + " - " + start + " = " + diff);
            float dist = diff.magnitude;
            if (dist < 0.001f) return;

            Vector3 wallPos = start + diff * 0.5f;
            Quaternion wallRot = Quaternion.LookRotation(diff);

            GameObject wall = Instantiate(wallPrefab, wallPos, wallRot, transform);
            wall.name = wallName;

            // Clean scale: thickness (X), height (Y), and distance (Z)
            // Use 1.0f for Y to preserve prefab height relative to its transform
            wall.transform.localScale = new Vector3(thickness, wall.transform.localScale.y, dist);

            currentWallPieces.Add(wall);
        }

        private enum PieceType
        {
            Straight,
            Turn45Left,
            Turn45Right,
            Turn90Left,
            Turn90Right
        }
    }
}

using UnityEngine;
using System.Collections;
using SharpNeat.Phenomes;
using System.Collections.Generic;
using SharpNeat.EvolutionAlgorithms;
using SharpNeat.Genomes.Neat;
using System;
using System.Xml;
using System.IO;
using CarExperiment;

public class Optimizer : MonoBehaviour {

    const int NUM_INPUTS = 5;
    const int NUM_OUTPUTS = 2;

    public int Trials;
    public float TrialDuration;
    public float StoppingFitness;
    bool EARunning;
    string popFileSavePath, champFileSavePath;

    SimpleExperiment experiment;
    static NeatEvolutionAlgorithm<NeatGenome> _ea;

    public GameObject Unit;
    public TrackGenerator trackGenerator;

    Dictionary<IBlackBox, UnitController> ControllerMap = new Dictionary<IBlackBox, UnitController>();
    private DateTime startTime;
    private float timeLeft;
    private float accum;
    private int frames;
    private float updateInterval = 12;

    private uint Generation;
    private double Fitness;

    private int episodeCount = 0;
    private float episodeStartTime;

    private int fixedUpdateCount = 0; // Added counter for FixedUpdate

	// Use this for initialization
	void Start () {
        Utility.DebugLog = true;
        experiment = new SimpleExperiment();
        XmlDocument xmlConfig = new XmlDocument();
        TextAsset textAsset = (TextAsset)Resources.Load("experiment.config");
        xmlConfig.LoadXml(textAsset.text);
        experiment.SetOptimizer(this);
        Debug.Log("Initializing experiment" + xmlConfig.DocumentElement.OuterXml);

        experiment.Initialize("Car Experiment", xmlConfig.DocumentElement, NUM_INPUTS, NUM_OUTPUTS);

        champFileSavePath = Application.persistentDataPath + string.Format("/{0}.champ.xml", "car");
        popFileSavePath = Application.persistentDataPath + string.Format("/{0}.pop.xml", "car");       

        print(champFileSavePath);
	}

    // Update is called once per frame
    void Update()
    {
      //  evaluationStartTime += Time.deltaTime;

        timeLeft -= Time.deltaTime;
        accum += Time.timeScale / Time.deltaTime;
        ++frames;
        //Debug.Log("Time left: " + timeLeft + ", Accum: " + accum + ", Frames: " + frames);

        if (timeLeft <= 0.0)
        {
            var fps = accum / frames;
            timeLeft = updateInterval;
            accum = 0.0f;
            frames = 0;
            //   print("FPS: " + fps);
            if (fps < 10)
            {
                Time.timeScale = Time.timeScale - 1;
                print("Lowering time scale to " + Time.timeScale);
            }
        }
    }

    void FixedUpdate() {
        fixedUpdateCount++; // Increment counter on each FixedUpdate
    }

    public void StartEA()
    {        
        Utility.DebugLog = true;
        Utility.Log("Starting PhotoTaxis experiment");
        // print("Loading: " + popFileLoadPath);
        _ea = experiment.CreateEvolutionAlgorithm(popFileSavePath);
        startTime = DateTime.Now;

        _ea.UpdateEvent += new EventHandler(ea_UpdateEvent);
        _ea.PausedEvent += new EventHandler(ea_PauseEvent);

        var evoSpeed = 1;

     //   Time.fixedDeltaTime = 0.045f;
        Time.timeScale = evoSpeed;       
        _ea.StartContinue();
        EARunning = true;
    }

    void ea_UpdateEvent(object sender, EventArgs e)
    {
        Utility.Log(string.Format("gen={0:N0} bestFitness={1:N6}",
            _ea.CurrentGeneration, _ea.Statistics._maxFitness));

        Fitness = _ea.Statistics._maxFitness;
        Generation = _ea.CurrentGeneration;

        // Get stats from static variables (set during GetFitness() before controller destruction)
        int champPieces = CarController.LastChampionPieces;
        int champWallHits = CarController.LastChampionWallHits;

        Logger.LogEpisode(
            "NEAT",
            (int)Generation,
            champPieces,
            champWallHits,
            (float)Fitness,
            fixedUpdateCount // Added fixed update count to log
        );
    }

    void ea_PauseEvent(object sender, EventArgs e)
    {
        Time.timeScale = 1;
        Utility.Log("Done ea'ing (and neat'ing)");

        XmlWriterSettings _xwSettings = new XmlWriterSettings();
        _xwSettings.Indent = true;
        // Save genomes to xml file.        
        DirectoryInfo dirInf = new DirectoryInfo(Application.persistentDataPath);
        if (!dirInf.Exists)
        {
            Debug.Log("Creating subdirectory");
            dirInf.Create();
        }
        using (XmlWriter xw = XmlWriter.Create(popFileSavePath, _xwSettings))
        {
            experiment.SavePopulation(xw, _ea.GenomeList);
        }
        // Also save the best genome

        using (XmlWriter xw = XmlWriter.Create(champFileSavePath, _xwSettings))
        {
            experiment.SavePopulation(xw, new NeatGenome[] { _ea.CurrentChampGenome });
        }
        DateTime endTime = DateTime.Now;
        Utility.Log("Total time elapsed: " + (endTime - startTime));

        // (stream reading removed — not used)
        EARunning = false;        

    }

    public void StopEA()
    {

        if (_ea != null && _ea.RunState == SharpNeat.Core.RunState.Running)
        {
            _ea.Stop();
        }
    }

    public void Evaluate(IBlackBox box)
    {
        if (trackGenerator != null)
        {
            int seed = SeedManager.GetSeedForEpisode((int)_ea.CurrentGeneration);
            trackGenerator.GenerateTrack(seed);
        }
        GameObject obj = Instantiate(Unit, Unit.transform.position, Unit.transform.rotation) as GameObject;
        UnitController controller = obj.GetComponent<UnitController>();

        ControllerMap.Add(box, controller);

        controller.Activate(box);
    }

    public void StopEvaluation(IBlackBox box)
    {
        UnitController ct = ControllerMap[box];

        Destroy(ct.gameObject);
    }

    public void VisualizeNetwork()
    {
        NeatGenome genome = null;

        // Load the champion genome
        try
        {
            using (XmlReader xr = XmlReader.Create(champFileSavePath))
                genome = NeatGenomeXmlIO.ReadCompleteGenomeList(xr, false, (NeatGenomeFactory)experiment.CreateGenomeFactory())[0];
        }
        catch (Exception e)
        {
            Debug.LogError("Error loading champion genome: " + e.Message);
            return;
        }

        // Generate DOT format for GraphViz
        string dotFilePath = Application.persistentDataPath + "/network.dot";
        using (StreamWriter writer = new StreamWriter(dotFilePath))
        {
            writer.WriteLine("digraph NeatNetwork {");
            writer.WriteLine("  rankdir=LR;");
            writer.WriteLine("  node [shape=circle];");

            // Input nodes
            writer.WriteLine("  subgraph cluster_inputs {");
            writer.WriteLine("    label=\"Inputs\";");
            for (int i = 0; i < NUM_INPUTS; i++)
            {
                writer.WriteLine($"    input{i} [label=\"I{i}\", style=filled, fillcolor=lightblue];");
            }
            writer.WriteLine("  }");

            // Output nodes
            writer.WriteLine("  subgraph cluster_outputs {");
            writer.WriteLine("    label=\"Outputs\";");
            for (int i = 0; i < NUM_OUTPUTS; i++)
            {
                writer.WriteLine($"    output{i} [label=\"O{i}\", style=filled, fillcolor=lightgreen];");
            }
            writer.WriteLine("  }");

            // Hidden nodes
            writer.WriteLine("  subgraph cluster_hidden {");
            writer.WriteLine("    label=\"Hidden\";");
            HashSet<uint> hiddenNodes = new HashSet<uint>();
            foreach (var conn in genome.ConnectionGeneList)
            {
                if (conn.SourceNodeId >= NUM_INPUTS && conn.SourceNodeId < genome.NodeList.Count - NUM_OUTPUTS)
                    hiddenNodes.Add(conn.SourceNodeId);
                if (conn.TargetNodeId >= NUM_INPUTS && conn.TargetNodeId < genome.NodeList.Count - NUM_OUTPUTS)
                    hiddenNodes.Add(conn.TargetNodeId);
            }
            foreach (var nodeId in hiddenNodes)
            {
                writer.WriteLine($"    hidden{nodeId} [label=\"H{nodeId}\", style=filled, fillcolor=lightyellow];");
            }
            writer.WriteLine("  }");

            // Connections
            foreach (var conn in genome.ConnectionGeneList)
            {
                string sourceNode = conn.SourceNodeId < NUM_INPUTS ? $"input{conn.SourceNodeId}" : 
                                   conn.SourceNodeId >= genome.NodeList.Count - NUM_OUTPUTS ? $"output{conn.SourceNodeId - (genome.NodeList.Count - NUM_OUTPUTS)}" :
                                   $"hidden{conn.SourceNodeId}";

                string targetNode = conn.TargetNodeId < NUM_INPUTS ? $"input{conn.TargetNodeId}" :
                                   conn.TargetNodeId >= genome.NodeList.Count - NUM_OUTPUTS ? $"output{conn.TargetNodeId - (genome.NodeList.Count - NUM_OUTPUTS)}" :
                                   $"hidden{conn.TargetNodeId}";

                string color = conn.Weight > 0 ? "green" : "red";
                string style = conn.Weight > 0 ? "solid" : "dashed";
                writer.WriteLine($"  {sourceNode} -> {targetNode} [label=\"{conn.Weight:F2}\", color={color}, style={style}, penwidth={Math.Abs(conn.Weight) + 0.5}];");
            }

            writer.WriteLine("}");
        }

        Debug.Log($"Network visualization saved to: {dotFilePath}");
        Debug.Log($"Nodes: {genome.NodeList.Count}, Connections: {genome.ConnectionGeneList.Count}");
        Debug.Log("Open this file with GraphViz or online at: https://dreampuf.github.io/GraphvizOnline/");
    }

    public void RunBest()
    {
        Time.timeScale = 1;

        NeatGenome genome = null;


        // Try to load the genome from the XML document.
        try
        {
            using (XmlReader xr = XmlReader.Create(champFileSavePath))
                genome = NeatGenomeXmlIO.ReadCompleteGenomeList(xr, false, (NeatGenomeFactory)experiment.CreateGenomeFactory())[0];


        }
        catch (Exception e1)
        {
            // print(champFileLoadPath + " Error loading genome from file!\nLoading aborted.\n"
            //						  + e1.Message + "\nJoe: " + champFileLoadPath);
            return;
        }

        // Get a genome decoder that can convert genomes to phenomes.
        var genomeDecoder = experiment.CreateGenomeDecoder();

        // Decode the genome into a phenome (neural network).
        var phenome = genomeDecoder.Decode(genome);

        GameObject obj = Instantiate(Unit, Unit.transform.position, Unit.transform.rotation) as GameObject;
        UnitController controller = obj.GetComponent<UnitController>();

        ControllerMap.Add(phenome, controller);

        controller.Activate(phenome);
    }

    public float GetFitness(IBlackBox box)
    {
        if (ControllerMap.ContainsKey(box))
        {
            return ControllerMap[box].GetFitness();
        }
        return 0;
    }

    void OnGUI()
    {
        if (GUI.Button(new Rect(10, 10, 100, 40), "Start EA"))
        {
            StartEA();
        }
        if (GUI.Button(new Rect(10, 60, 100, 40), "Stop EA"))
        {
            StopEA();
        }
        if (GUI.Button(new Rect(10, 110, 100, 40), "Run best"))
        {
            RunBest();
        }
        if (GUI.Button(new Rect(10, 160, 100, 40), "Visualize Net"))
        {
            VisualizeNetwork();
        }

        GUI.Button(new Rect(10, Screen.height - 70, 100, 60), string.Format("Generation: {0}\nFitness: {1:0.00}", Generation, Fitness));
    }

    public UnitController GetController(IBlackBox box)
    {
        if (ControllerMap.ContainsKey(box))
            return ControllerMap[box];

        return null;
    }
}

using UnityEngine;
using System.Collections;
using SharpNeat.Phenomes;
using System.Collections.Generic;
using SharpNeat.EvolutionAlgorithms;
using SharpNeat.Genomes.Neat;
using System;
using System.Xml;
using System.IO;
using CarExperiment;

public class Optimizer : MonoBehaviour {

    const int NUM_INPUTS = 5;
    const int NUM_OUTPUTS = 2;

    public int Trials;
    public float TrialDuration;
    public float StoppingFitness;
    bool EARunning;
    string popFileSavePath, champFileSavePath;

    SimpleExperiment experiment;
    static NeatEvolutionAlgorithm<NeatGenome> _ea;

    public GameObject Unit;
    public TrackGenerator trackGenerator;

    Dictionary<IBlackBox, UnitController> ControllerMap = new Dictionary<IBlackBox, UnitController>();
    // Store evaluation results for the current generation so we can log stats for the best-evaluated phenome
    class EvalResult { public float fitness; public int pieces; public int wallHits; }
    List<EvalResult> _evalResults = new List<EvalResult>();
    private DateTime startTime;
    private float timeLeft;
    private float accum;
    private int frames;
    private float updateInterval = 12;

    private uint Generation;
    private double Fitness;

    private int episodeCount = 0;
    private float episodeStartTime;

    private int fixedUpdateCount = 0; // Added counter for FixedUpdate

	// Use this for initialization
	void Start () {
        Utility.DebugLog = true;
        experiment = new SimpleExperiment();
        XmlDocument xmlConfig = new XmlDocument();
        TextAsset textAsset = (TextAsset)Resources.Load("experiment.config");
        xmlConfig.LoadXml(textAsset.text);
        experiment.SetOptimizer(this);
        Debug.Log("Initializing experiment" + xmlConfig.DocumentElement.OuterXml);

        experiment.Initialize("Car Experiment", xmlConfig.DocumentElement, NUM_INPUTS, NUM_OUTPUTS);

        champFileSavePath = Application.persistentDataPath + string.Format("/{0}.champ.xml", "car");
        popFileSavePath = Application.persistentDataPath + string.Format("/{0}.pop.xml", "car");       

        print(champFileSavePath);
	}

    // Update is called once per frame
    void Update()
    {
      //  evaluationStartTime += Time.deltaTime;

        timeLeft -= Time.deltaTime;
        accum += Time.timeScale / Time.deltaTime;
        ++frames;
        //Debug.Log("Time left: " + timeLeft + ", Accum: " + accum + ", Frames: " + frames);

        if (timeLeft <= 0.0)
        {
            var fps = accum / frames;
            timeLeft = updateInterval;
            accum = 0.0f;
            frames = 0;
            //   print("FPS: " + fps);
            if (fps < 10)
            {
                Time.timeScale = Time.timeScale - 1;
                print("Lowering time scale to " + Time.timeScale);
            }
        }
    }

    void FixedUpdate() {
        fixedUpdateCount++; // Increment counter on each FixedUpdate
    }

    public void StartEA()
    {        
        Utility.DebugLog = true;
        Utility.Log("Starting PhotoTaxis experiment");
        // print("Loading: " + popFileLoadPath);
        _ea = experiment.CreateEvolutionAlgorithm(popFileSavePath);
        startTime = DateTime.Now;

        _ea.UpdateEvent += new EventHandler(ea_UpdateEvent);
        _ea.PausedEvent += new EventHandler(ea_PauseEvent);

        var evoSpeed = 1;

     //   Time.fixedDeltaTime = 0.045f;
        Time.timeScale = evoSpeed;       
        _ea.StartContinue();
        EARunning = true;
    }

    void ea_UpdateEvent(object sender, EventArgs e)
    {
        Utility.Log(string.Format("gen={0:N0} bestFitness={1:N6}",
            _ea.CurrentGeneration, _ea.Statistics._maxFitness));

        Fitness = _ea.Statistics._maxFitness;
        Generation = _ea.CurrentGeneration;
        // Determine the evaluated phenome with highest fitness this generation (if we have results)
        int champPieces = 0;
        int champWallHits = 0;
        if(_evalResults != null && _evalResults.Count > 0)
        {
            float bestFit = float.MinValue;
            EvalResult best = null;
            foreach(var r in _evalResults)
            {
                if(r.fitness > bestFit)
                {
                    bestFit = r.fitness;
                    best = r;
                }
            }
            if(best != null)
            {
                champPieces = best.pieces;
                champWallHits = best.wallHits;
            }
        }
        else
        {
            // Fallback to static fields if no per-generation results collected
            champPieces = CarController.LastChampionPieces;
            champWallHits = CarController.LastChampionWallHits;
        }

        Debug.Log($"[Optimizer] Logging generation stats: gen={Generation}, bestFitness={Fitness}, pieces={champPieces}, wallHits={champWallHits}");

        Logger.LogEpisode(
            "NEAT",
            (int)Generation,
            champPieces,
            champWallHits,
            (float)Fitness,
            fixedUpdateCount // Added fixed update count to log
        );

        // Clear results buffer for next generation
        _evalResults.Clear();
    }

    void ea_PauseEvent(object sender, EventArgs e)
    {
        Time.timeScale = 1;
        Utility.Log("Done ea'ing (and neat'ing)");

        XmlWriterSettings _xwSettings = new XmlWriterSettings();
        _xwSettings.Indent = true;
        // Save genomes to xml file.        
        DirectoryInfo dirInf = new DirectoryInfo(Application.persistentDataPath);
        if (!dirInf.Exists)
        {
            Debug.Log("Creating subdirectory");
            dirInf.Create();
        }
        using (XmlWriter xw = XmlWriter.Create(popFileSavePath, _xwSettings))
        {
            experiment.SavePopulation(xw, _ea.GenomeList);
        }
        // Also save the best genome

        using (XmlWriter xw = XmlWriter.Create(champFileSavePath, _xwSettings))
        {
            experiment.SavePopulation(xw, new NeatGenome[] { _ea.CurrentChampGenome });
        }
        DateTime endTime = DateTime.Now;
        Utility.Log("Total time elapsed: " + (endTime - startTime));

        // (stream reading removed — not used)
        EARunning = false;        

    }

    public void StopEA()
    {

        if (_ea != null && _ea.RunState == SharpNeat.Core.RunState.Running)
        {
            _ea.Stop();
        }
    }

    public void Evaluate(IBlackBox box)
    {
        if (trackGenerator != null)
        {
            int seed = SeedManager.GetSeedForEpisode((int)_ea.CurrentGeneration);
            trackGenerator.GenerateTrack(seed);
        }
        GameObject obj = Instantiate(Unit, Unit.transform.position, Unit.transform.rotation) as GameObject;
        UnitController controller = obj.GetComponent<UnitController>();

        ControllerMap.Add(box, controller);

        controller.Activate(box);
    }

    public void StopEvaluation(IBlackBox box)
    {
        UnitController ct = ControllerMap[box];

        // Record final stats for this evaluation before destroying the GameObject
        try
        {
            float fit = ct.GetFitness();
            int pieces = 0;
            int wallHits = 0;
            // If this controller is a CarController, retrieve the extra stats
            CarController carCt = ct as CarController;
            if(carCt != null)
            {
                pieces = carCt.GetPieces();
                wallHits = carCt.GetWallHits();
            }
            _evalResults.Add(new EvalResult { fitness = fit, pieces = pieces, wallHits = wallHits });
            Debug.Log($"[Optimizer] Eval recorded: fitness={fit}, pieces={pieces}, wallHits={wallHits}");
        }
        catch (Exception ex)
        {
            Debug.LogWarning("Failed to record eval stats: " + ex.Message);
        }

        // Remove mapping and destroy controller
        ControllerMap.Remove(box);
        Destroy(ct.gameObject);
    }

